func buildAgentContextEnrichment(cfg *config.Config) agentContextEnrichment {
	out := agentContextEnrichment{authStatus: "missing"}
	if cfg != nil {
		out.defaultRestaurant = cfg.DefaultRestaurant
		if cfg.DefaultMax > 0 || cfg.DefaultTipPct > 0 {
			out.budgetHint = map[string]any{"default_max": cfg.DefaultMax, "default_tip_pct": cfg.DefaultTipPct}
		}
		if cfg.AuthHeader() != "" {
			out.authStatus = fmt.Sprintf("configured (%s)", cfg.AuthSource)
		}
	}
	db, err := store.OpenReadOnly(defaultDBPath("ordertogo-pp-cli"))
	if err != nil {
		return out
	}
	defer db.Close()
	last, err := db.LastOrder(out.defaultRestaurant)
	if err == nil && last != nil {
		summary := orderOutput(last)
		out.lastOrderSummary = summary
		if !last.OrderedAt.IsZero() {
			days := int(time.Since(last.OrderedAt).Hours() / 24)
			out.daysSinceLastOrder = &days
		}
	}
	orders, err := db.RecentOrders(out.defaultRestaurant, 200)
	if err == nil && len(orders) > 0 {
		counts := map[string]int{}
		byKey := map[string]store.Order{}
		for _, order := range orders {
			key := sortedItemTuple(order.Items)
			if key == "" {
				continue
			}
			counts[key]++
			if existing, ok := byKey[key]; !ok || order.OrderedAt.After(existing.OrderedAt) {
				byKey[key] = order
			}
		}
		bestKey := ""
		for key, count := range counts {
			if count > counts[bestKey] {
				bestKey = key
			}
		}
		if bestKey != "" {
			order := byKey[bestKey]
			out.usual = map[string]any{"restaurant": order.Restaurant, "items": order.Items, "frequency": counts[bestKey]}
		}
	}
	return out
}

